@app.route("/login", methods=["GET","POST"])
def login():
    error = None
    if request.method == "POST":
        username = request.form.get("username","").strip()
        password = request.form.get("password","").strip()
        if username in USERS and USERS[username] == password:
            session["logged_in"] = True
            session["username"] = username
            return redirect(url_for("index"))
        else:
            error = "Invalid username or password. Please try again."
    return render_template_string(LOGIN_HTML, error=error)

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login"))

@app.route("/")
def index():
    if not session.get("logged_in"):
        return redirect(url_for("login"))
    return render_template_string(HTML)

@app.route("/chat", methods=["POST"])
def chat():
    if not session.get("logged_in"):
        return jsonify({"error":"unauthorized"}), 401
    data = request.get_json()
    user_input = data.get("message","")
    match = match_query(user_input)
    if match:
        return jsonify({"reply":match["reply"],"link":match["link"],"label":match["label"]})
    else:
        return jsonify({
            "reply":"I'm sorry, I didn't understand that.<br>Please use the quick chips or type keywords like:<br>&#8226; Setup File &nbsp;&#8226; CRM Login &nbsp;&#8226; Delete Query<br>&#8226; SQL Install &nbsp;&#8226; MS Office &nbsp;&#8226; Downloader",
            "link":None,"label":None
        })

@app.route("/version")
def version():
    return jsonify({"version": get_local_version(), "updater": UPDATER_AVAILABLE})

@app.route("/check-update")
def check_update_route():
    if not session.get("logged_in"):
        return jsonify({"error":"unauthorized"}), 401
    if not UPDATER_AVAILABLE:
        return jsonify({"status":"unavailable"})
    found, local, remote = check_for_update()
    return jsonify({"update_available": found, "local": local, "remote": remote})

@app.route("/do-update", methods=["POST"])
def do_update_route():
    if not session.get("logged_in"):
        return jsonify({"error":"unauthorized"}), 401
    if not UPDATER_AVAILABLE:
        return jsonify({"status":"unavailable"})
    import threading
    def run():
        ok, path = download_new_exe()
        if ok:
            restart_app(path)
    threading.Thread(target=run, daemon=True).start()
    return jsonify({"status":"updating"})

def open_browser():
    webbrowser.open("http://127.0.0.1:5000")

if __name__ == "__main__":
    if os.environ.get("WERKZEUG_RUN_MAIN") != "true":
        threading.Timer(1.5, open_browser).start()
    app.run(debug=False, port=5000, use_reloader=False)
